#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e6 + 5;
ll n, w[MAXN], c[MAXN], ans[MAXN];
vector <ll> ve[MAXN], s;
void dfs(int u)
{
	s.push_back(s.back() + w[u]);
	ll sum = 0 ;
	ll l = 0, r = s.size() - 1;
	while (l <= r)
	{
		ll mid = (l + r) / 2;
		if (s[s.size() - 1] - s[mid] <= c[u] )
		{
			sum = mid;
			r = mid - 1;
		}
		else l = mid + 1;
	}
	ans[u] = s.size() - sum - 1;
	for (auto v : ve[u])
	{
		dfs(v);
	}
	s.pop_back();
}
int main(void)
{
	cin >> n;
	for (int i = 2, p; i <= n; ++i)
	{
		cin >> p;
		ve[p].push_back(i);
	}
	for (int i = 1; i <= n; ++i)
	{
		cin >> w[i];
	}
	for (int i = 1; i <= n; ++i)
	{
		cin >> c[i];
	}
	s.push_back(0);
	dfs(1);
	for (int i = 1; i <= n; ++i)
	{
		cout << ans[i] << ' ';
	}
	return false;
}
